INSERT INTO modules (slug, titulo, subtitulo, orden, estado) VALUES ('bloque-1', 'Cómo piensan las computadoras', 'Lógica, binario y procesamiento', 1, 'publicado'), ('bloque-1-5', 'Cómo se ejecuta un programa', 'Del código al resultado', 1.5, 'publicado'), ('bloque-2', 'Cómo se guarda la información', 'Bases de datos, archivos y almacenamiento', 2, 'publicado'), ('bloque-3', 'Cómo se conectan las cosas', 'Redes, internet y APIs', 3, 'publicado'), ('bloque-4', 'Seguridad y privacidad', 'Proteger datos y sistemas', 4, 'publicado'), ('bloque-5', 'Cómo nace un producto digital', 'Del problema a la solución', 5, 'publicado'), ('bloque-6', 'Qué es la IA', 'Inteligencia artificial sin misterio', 6, 'publicado') ON CONFLICT (slug) DO NOTHING;
INSERT INTO nodes (module_id, slug, titulo, resumen_corto, tipo, aprendizaje_tipo, dificultad, orden_en_modulo, estado, es_clave) VALUES ((SELECT id FROM modules WHERE slug = 'bloque-1'), 'que-es-una-computadora', 'Qué es una computadora', 'Una máquina que sigue instrucciones', 'concepto', 'fundamento', 1, 1, 'publicado', true), ((SELECT id FROM modules WHERE slug = 'bloque-1'), 'como-piensa-en-numeros', 'Cómo piensa en números', 'Todo se reduce a ceros y unos', 'concepto', 'fundamento', 1, 2, 'publicado', true), ((SELECT id FROM modules WHERE slug = 'bloque-1'), 'que-es-un-algoritmo', 'Qué es un algoritmo', 'Una receta paso a paso', 'concepto', 'fundamento', 1, 3, 'publicado', true), ((SELECT id FROM modules WHERE slug = 'bloque-6'), 'que-es-la-ia', 'Qué es la inteligencia artificial', 'Máquinas que aprenden de datos', 'concepto', 'ia', 1, 1, 'publicado', true), ((SELECT id FROM modules WHERE slug = 'bloque-5'), 'del-problema-al-producto', 'Del problema al producto', 'Cómo nace una idea digital', 'concepto', 'producto', 1, 1, 'publicado', true) ON CONFLICT (slug) DO NOTHING;
INSERT INTO node_sections (node_id, section_type, titulo, contenido_md, orden, es_opcional) SELECT n.id, v.section_type, v.titulo, v.contenido_md, v.orden, v.es_opcional FROM nodes n JOIN (VALUES ('que-es-una-computadora', 'intro', 'Introducción', 'Una computadora es una máquina que recibe instrucciones, las procesa y devuelve un resultado. Nada más y nada menos.', 1, false), ('que-es-una-computadora', 'en_criollo', 'Pensalo así', 'Imaginá una receta de cocina: vos le das los ingredientes (datos) y los pasos (instrucciones), y la computadora te devuelve el plato terminado (resultado).', 2, false), ('que-es-una-computadora', 'profundizacion', 'Para saber más', 'Las computadoras modernas pueden ejecutar miles de millones de instrucciones por segundo. Pero cada una de esas instrucciones es extremadamente simple.', 3, true), ('como-piensa-en-numeros', 'intro', 'Introducción', 'Las computadoras solo entienden dos cosas: encendido y apagado. Eso se representa con 1 y 0. A eso le llamamos sistema binario.', 1, false), ('como-piensa-en-numeros', 'explicacion_central', 'Ejemplo concreto', 'El número 5 en binario se escribe 101. El número 3 se escribe 11. Todo lo que ves en pantalla — letras, colores, sonidos — es una combinación de ceros y unos.', 2, false), ('que-es-un-algoritmo', 'intro', 'Introducción', 'Un algoritmo es una serie de pasos ordenados para resolver un problema. No es algo exclusivo de las computadoras — vos usás algoritmos todos los días.', 1, false), ('que-es-un-algoritmo', 'en_criollo', 'Pensalo así', 'Cuando seguís una receta de cocina, estás ejecutando un algoritmo. Paso 1: hervir agua. Paso 2: agregar fideos. Paso 3: esperar 8 minutos.', 2, false), ('que-es-la-ia', 'intro', 'Introducción', 'La inteligencia artificial es un conjunto de técnicas que permiten a las máquinas aprender de datos y tomar decisiones sin que alguien las programe paso a paso.', 1, false), ('del-problema-al-producto', 'intro', 'Introducción', 'Todo producto digital nace de un problema real. Alguien necesita algo, y alguien diseña una solución. Así nacen las apps, las plataformas y los sitios web.', 1, false)) AS v(node_slug, section_type, titulo, contenido_md, orden, es_opcional) ON n.slug = v.node_slug WHERE NOT EXISTS (SELECT 1 FROM node_sections ns WHERE ns.node_id = n.id AND ns.section_type = v.section_type AND ns.orden = v.orden);
INSERT INTO learning_paths (slug, nombre, descripcion) VALUES ('ruta-evolutiva', 'Ruta evolutiva', 'Recorrido completo y secuencial por todos los bloques'), ('ruta-ia', 'Ruta IA', 'Enfocada en entender inteligencia artificial y sus aplicaciones'), ('ruta-producto', 'Ruta producto', 'Cómo se diseñan y construyen productos digitales'), ('ruta-seguridad', 'Ruta seguridad', 'Protección de datos, privacidad y riesgos digitales') ON CONFLICT (slug) DO NOTHING;
INSERT INTO learning_path_nodes (path_id, node_id, orden, es_opcional) VALUES ((SELECT id FROM learning_paths WHERE slug = 'ruta-evolutiva'), (SELECT id FROM nodes WHERE slug = 'que-es-una-computadora'), 1, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-evolutiva'), (SELECT id FROM nodes WHERE slug = 'como-piensa-en-numeros'), 2, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-evolutiva'), (SELECT id FROM nodes WHERE slug = 'que-es-un-algoritmo'), 3, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-evolutiva'), (SELECT id FROM nodes WHERE slug = 'del-problema-al-producto'), 4, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-evolutiva'), (SELECT id FROM nodes WHERE slug = 'que-es-la-ia'), 5, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-ia'), (SELECT id FROM nodes WHERE slug = 'que-es-una-computadora'), 1, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-ia'), (SELECT id FROM nodes WHERE slug = 'que-es-la-ia'), 2, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-producto'), (SELECT id FROM nodes WHERE slug = 'que-es-una-computadora'), 1, false), ((SELECT id FROM learning_paths WHERE slug = 'ruta-producto'), (SELECT id FROM nodes WHERE slug = 'del-problema-al-producto'), 2, false) ON CONFLICT (path_id, node_id) DO NOTHING;
INSERT INTO entry_questions (slug, pregunta, tipo, orden) VALUES ('nivel-actual', '¿Cuánto sabés de tecnología?', 'single_choice', 1), ('objetivo-principal', '¿Qué te gustaría lograr?', 'single_choice', 2), ('forma-de-aprender', '¿Cómo preferís aprender?', 'single_choice', 3) ON CONFLICT (slug) DO NOTHING;
INSERT INTO entry_question_options (question_id, valor, label, descripcion, orden) SELECT q.id, v.valor, v.label, v.descripcion, v.orden FROM entry_questions q JOIN (VALUES ('nivel-actual', 'nulo', 'Arranco de cero', 'No tengo experiencia con tecnología', 1), ('nivel-actual', 'basico', 'Sé lo básico', 'Uso apps y herramientas, pero no entiendo cómo funcionan por dentro', 2), ('nivel-actual', 'medio', 'Tengo algo de contexto', 'Entiendo algunos conceptos pero me faltan conexiones', 3), ('objetivo-principal', 'entender', 'Entender cómo funciona todo', 'Quiero una visión general del mundo tech', 1), ('objetivo-principal', 'ia', 'Entender la IA', 'Me interesa saber qué es y cómo se usa', 2), ('objetivo-principal', 'producto', 'Crear un producto digital', 'Quiero saber cómo nacen las apps y plataformas', 3), ('objetivo-principal', 'seguridad', 'Proteger mis datos', 'Me preocupa la privacidad y seguridad digital', 4), ('forma-de-aprender', 'lectura', 'Leyendo a mi ritmo', 'Prefiero leer y explorar por mi cuenta', 1), ('forma-de-aprender', 'ejemplos', 'Con ejemplos reales', 'Aprendo mejor viendo casos concretos', 2), ('forma-de-aprender', 'guiado', 'Con un recorrido guiado', 'Prefiero que me digan por dónde empezar', 3)) AS v(q_slug, valor, label, descripcion, orden) ON q.slug = v.q_slug WHERE NOT EXISTS (SELECT 1 FROM entry_question_options eqo WHERE eqo.question_id = q.id AND eqo.valor = v.valor);
